+  EXPECT_NEAR(v2.x(), 0,epsilon); 
+  EXPECT_NEAR(v2.y(), 0,epsilon); 
+  EXPECT_NEAR(v2.z(), -1,epsilon); 
+                 
+  //Roll by 90
+  yaw = 0;
+  pitch = 0;
+  roll = M_PI/2;
+  
+  q = btQuaternion(0,0,0);
+  v = btVector3(0,1,0);
