+  printf("%f, %f, %f: yaw and roll by %f -> %f, %f, %f\n", v.x(), v.y(), v.z(), roll, v2.x(), v2.y(), v2.z());
+  EXPECT_NEAR(v2.x(), 1,epsilon); 
