+
+  cache_time.fromSec(tf::Transformer::DEFAULT_CACHE_TIME);
+
+  if (!PyArg_ParseTuple(args, "|iO&", &interpolating, rosduration_converter, &cache_time))
+    return -1;
+
+  ((transformer_t*)self)->t = new tf::Transformer(interpolating, cache_time);
+
+  return 0;
+}
