+  transformer_Type.tp_alloc = PyType_GenericAlloc;
+  transformer_Type.tp_new = PyType_GenericNew;
+  transformer_Type.tp_init = Transformer_init;
+  transformer_Type.tp_flags = Py_TPFLAGS_DEFAULT | Py_TPFLAGS_BASETYPE;
