+	void callback()
+	{
+		++count_;
+
+		//printf("Counter: %d\n", count_);
+
+		if (count_ == expected_count_)
+		{
+		  boost::timed_mutex::scoped_lock* lock = lock_;
+      lock_ = 0;
+      delete lock;
+		}
+	}
